package ru.memearena.analytics.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="product_event") public class ProductEvent { @Id private UUID id; @Column(name="user_id") private UUID userId; @Column(name="installation_id",length=100) private String installationId; @Enumerated(EnumType.STRING) @Column(name="event_type",nullable=false,length=50) private ProductEventType eventType; @Column(nullable=false,length=20) private String source; @Column(name="occurred_at",nullable=false) private Instant occurredAt; @Column(name="received_at",nullable=false) private Instant receivedAt; @Column(name="app_version",length=30) private String appVersion; @Column(length=20) private String platform; protected ProductEvent(){} public ProductEvent(UUID id,UUID userId,String installationId,ProductEventType eventType,String source,Instant occurredAt,Instant receivedAt,String appVersion,String platform){this.id=id;this.userId=userId;this.installationId=installationId;this.eventType=eventType;this.source=source;this.occurredAt=occurredAt;this.receivedAt=receivedAt;this.appVersion=appVersion;this.platform=platform;} }
